function myAlgorithm(id, grid, size) {
  const EMPTY = -1;
  const center = (size - 1) / 2;
  const radius = size / 2;

  // Find all frontier cells: empty cells adjacent to my territory
  const frontier = [];
  const seen = new Set();

  // Also track enemy positions for threat assessment
  let myCount = 0;
  const enemyCells = [];

  for (let r = 0; r < size; r++) {
    for (let c = 0; c < size; c++) {
      const v = grid[r][c];
      if (v === id) {
        myCount++;
      } else if (v !== null && v !== EMPTY && v !== id) {
        enemyCells.push([r, c]);
      }
    }
  }

  // Find frontier
  for (let r = 0; r < size; r++) {
    for (let c = 0; c < size; c++) {
      if (grid[r][c] !== id) continue;
      const neighbors = [[r-1,c],[r+1,c],[r,c-1],[r,c+1]];
      for (const [nr, nc] of neighbors) {
        if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
        if (grid[nr][nc] !== EMPTY) continue;
        const key = nr * size + nc;
        if (seen.has(key)) continue;
        seen.add(key);
        frontier.push([nr, nc]);
      }
    }
  }

  if (frontier.length === 0) return [];

  // Score each frontier cell
  // Priorities:
  // 1. Cells with more empty neighbors (expansion potential)
  // 2. Cells far from enemies (safer territory) but close enough to race
  // 3. Cells closer to open areas

  const scored = frontier.map(([r, c]) => {
    let score = 0;

    // Count empty neighbors (8-directional for potential)
    let emptyNeighbors = 0;
    let enemyNeighbors = 0;
    let myNeighbors = 0;
    for (let dr = -1; dr <= 1; dr++) {
      for (let dc = -1; dc <= 1; dc++) {
        if (dr === 0 && dc === 0) continue;
        const nr = r + dr, nc = c + dc;
        if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
        const v = grid[nr][nc];
        if (v === EMPTY) emptyNeighbors++;
        else if (v === id) myNeighbors++;
        else if (v !== null) enemyNeighbors++;
      }
    }

    score += emptyNeighbors * 3;

    // Racing toward enemies - claim contested territory first
    if (enemyNeighbors > 0) {
      score += 10; // block enemy expansion
    }

    // Distance from center - prefer expanding outward for more area,
    // but slight preference for spreading rather than filling
    const dr2 = r - center;
    const dc2 = c - center;
    const distFromCenter = Math.sqrt(dr2*dr2 + dc2*dc2);

    // Find nearest enemy
    let minEnemyDist = Infinity;
    for (const [er, ec] of enemyCells) {
      const d = Math.abs(er - r) + Math.abs(ec - c);
      if (d < minEnemyDist) minEnemyDist = d;
    }

    // Race toward contested frontiers - cells near enemies are urgent
    if (minEnemyDist < 10) {
      score += (10 - minEnemyDist) * 2;
    }

    // Prefer cells that extend outward (have fewer of my neighbors)
    // to maximize frontier length
    score -= myNeighbors * 0.5;

    return { cell: [r, c], score };
  });

  scored.sort((a, b) => b.score - a.score);

  return scored.map(s => s.cell);
}
