  const EMPTY = -1;
  const center = (size - 1) / 2;
  const radius = size / 2;

  // Scan grid
  let myCount = 0;
  const enemyCells = [];
  const myCells = [];
  let totalEmpty = 0;

  for (let r = 0; r < size; r++) {
    for (let c = 0; c < size; c++) {
      const v = grid[r][c];
      if (v === id) {
        myCount++;
        myCells.push([r, c]);
      } else if (v === EMPTY) {
        totalEmpty++;
      } else if (v !== null && v !== EMPTY) {
        enemyCells.push([r, c]);
      }
    }
  }

  // BFS distance from enemies (multi-source) - limited depth
  const MAX_DIST = 15;
  const enemyDist = new Array(size * size).fill(Infinity);
  const myDist = new Array(size * size).fill(Infinity);

  // BFS from enemies through empty+my cells (but enemies block)
  let queue = [];
  for (const [r, c] of enemyCells) {
    const k = r * size + c;
    enemyDist[k] = 0;
    queue.push([r, c, 0]);
  }
  let head = 0;
  while (head < queue.length) {
    const [r, c, d] = queue[head++];
    if (d >= MAX_DIST) continue;
    const nbrs = [[r-1,c],[r+1,c],[r,c-1],[r,c+1]];
    for (const [nr, nc] of nbrs) {
      if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
      const v = grid[nr][nc];
      if (v === null) continue;
      const nk = nr * size + nc;
      if (enemyDist[nk] <= d + 1) continue;
      // Don't propagate through my cells (they're a wall from enemy perspective for racing)
      if (v === id) continue;
      enemyDist[nk] = d + 1;
      queue.push([nr, nc, d + 1]);
    }
  }

  // BFS from my cells through empty cells
  queue = [];
  head = 0;
  for (const [r, c] of myCells) {
    const k = r * size + c;
    myDist[k] = 0;
    queue.push([r, c, 0]);
  }
  while (head < queue.length) {
    const [r, c, d] = queue[head++];
    if (d >= MAX_DIST) continue;
    const nbrs = [[r-1,c],[r+1,c],[r,c-1],[r,c+1]];
    for (const [nr, nc] of nbrs) {
      if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
      const v = grid[nr][nc];
      if (v === null) continue;
      if (v !== EMPTY && v !== id) continue;
      const nk = nr * size + nc;
      if (myDist[nk] <= d + 1) continue;
      myDist[nk] = d + 1;
      queue.push([nr, nc, d + 1]);
    }
  }

  // Find frontier
  const frontier = [];
  const seen = new Set();
  for (let i = 0; i < myCells.length; i++) {
    const [r, c] = myCells[i];
    const nbrs = [[r-1,c],[r+1,c],[r,c-1],[r,c+1]];
    for (const [nr, nc] of nbrs) {
      if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
      if (grid[nr][nc] !== EMPTY) continue;
      const key = nr * size + nc;
      if (seen.has(key)) continue;
      seen.add(key);
      frontier.push([nr, nc]);
    }
  }

  if (frontier.length === 0) return [];

  // Score each frontier cell
  const scored = frontier.map(([r, c]) => {
    let score = 0;
    const k = r * size + c;

    // Count neighbors
    let emptyN4 = 0, enemyN4 = 0, myN4 = 0;
    const n4 = [[r-1,c],[r+1,c],[r,c-1],[r,c+1]];
    for (const [nr, nc] of n4) {
      if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
      const v = grid[nr][nc];
      if (v === EMPTY) emptyN4++;
      else if (v === id) myN4++;
      else if (v !== null) enemyN4++;
    }

    // Count 8-dir empty for expansion potential
    let emptyN8 = 0;
    for (let dr = -1; dr <= 1; dr++) {
      for (let dc = -1; dc <= 1; dc++) {
        if (dr === 0 && dc === 0) continue;
        const nr = r + dr, nc = c + dc;
        if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
        if (grid[nr][nc] === EMPTY) emptyN8++;
      }
    }

    score += emptyN8 * 2;
    score += emptyN4 * 3;

    const ed = enemyDist[k];
    const md = myDist[k];

    // CRITICAL: Race for contested territory
    // If we can reach this cell before the enemy, it's valuable
    // If enemy is very close, we MUST claim it now to block
    if (ed !== Infinity) {
      if (ed <= 2) {
        score += 50; // blocking move, very urgent
      } else if (ed <= 5) {
        score += 30 - ed * 3;
      } else if (ed <= 10) {
        score += 15 - ed;
      }

      // If we're closer than enemy, prioritize reaching midpoint
      if (md < ed) {
        score += (ed - md) * 2;
      }
    } else {
      // No enemy threat - focus on pure expansion
      score += emptyN8 * 1.5;
    }

    // Prefer extending (fewer own neighbors = more frontier growth)
    score -= myN4 * 1.5;

    // Slight bias toward center-mass expansion for circular arena
    const dr2 = r - center;
    const dc2 = c - center;
    const dist = Math.sqrt(dr2*dr2 + dc2*dc2);
    // Prefer cells that are well inside the circle (not wasted on edge)
    if (dist < radius * 0.85) {
      score += 1;
    }

    return { cell: [r, c], score };
  });

  scored.sort((a, b) => b.score - a.score);

  return scored.map(s => s.cell);
}

