  for (let r = 0; r < H; r++) {
    const row = grid[r];
    let base = r * W;
    for (let c = 0; c < W; c++) {
      const v = row[c];
      const i = base + c;
      if (v === null) {
        inside[i] = 0;
        flat[i] = -2; // outside
      } else {
        inside[i] = 1;
        flat[i] = v;
        if (v === id) ourCount++;
      }
    }
  }
  if (ourCount === 0) return [];

  // Distance from our territories and enemies across EMPTY cells only
  const INF = -1;
  const distOur = new Int16Array(N);
  const distEnemy = new Int16Array(N);
  for (let i = 0; i < N; i++) { distOur[i] = INF; distEnemy[i] = INF; }

  const qOur = new Int32Array(N);
  const qEnemy = new Int32Array(N);
  let qOurHead = 0, qOurTail = 0;
  let qEnemyHead = 0, qEnemyTail = 0;

  for (let i = 0; i < N; i++) {
    if (!inside[i]) continue;
    const v = flat[i];
    if (v === id) {
      distOur[i] = 0;
      qOur[qOurTail++] = i;
    } else if (v >= 0 && v !== id) {
      distEnemy[i] = 0;
      qEnemy[qEnemyTail++] = i;
    }
  }

  function bfsEmpty(queue, head, tail, distArr) {
    while (head < tail) {
      const idx = queue[head++];
      const r = (idx / W) | 0;
      const c = idx % W;

      // Up
      if (r > 0) {
        const ni = idx - W;
        if (inside[ni] && flat[ni] === EMPTY && distArr[ni] === INF) {
          distArr[ni] = distArr[idx] + 1;
          queue[tail++] = ni;
        }
      }
      // Down
      if (r + 1 < H) {
        const ni = idx + W;
        if (inside[ni] && flat[ni] === EMPTY && distArr[ni] === INF) {
          distArr[ni] = distArr[idx] + 1;
          queue[tail++] = ni;
        }
      }
      // Left
      if (c > 0) {
        const ni = idx - 1;
        if (inside[ni] && flat[ni] === EMPTY && distArr[ni] === INF) {
          distArr[ni] = distArr[idx] + 1;
          queue[tail++] = ni;
        }
      }
      // Right
      if (c + 1 < W) {
        const ni = idx + 1;
        if (inside[ni] && flat[ni] === EMPTY && distArr[ni] === INF) {
          distArr[ni] = distArr[idx] + 1;
          queue[tail++] = ni;
        }
      }
    }
    return [head, tail];
  }

  [qOurHead, qOurTail] = bfsEmpty(qOur, qOurHead, qOurTail, distOur);
  [qEnemyHead, qEnemyTail] = bfsEmpty(qEnemy, qEnemyHead, qEnemyTail, distEnemy);

  // Advantage map: enemyDist - ourDist (bigger is better for us)
  const advMap = new Int16Array(N);
  const isTie = new Uint8Array(N);
  for (let i = 0; i < N; i++) {
    if (!inside[i] || flat[i] !== EMPTY) {
      advMap[i] = -32768;
      isTie[i] = 0;
      continue;
    }
    const do_ = distOur[i], de_ = distEnemy[i];
    const Do = (do_ < 0 ? 1000 : do_);
    const De = (de_ < 0 ? 1000 : de_);
    const adv = De - Do;
    advMap[i] = adv;
    isTie[i] = (adv === 0) ? 1 : 0;
  }

  // Label positive-advantage components and tie components
  const q = new Int32Array(N);

  // Helper to label components given a predicate on adv value
  function labelComponents(matchValue) {
    const compId = new Int32Array(N);
    for (let i = 0; i < N; i++) compId[i] = -1;
    const sizes = [];
    for (let i = 0; i < N; i++) {
      if (!inside[i] || flat[i] !== EMPTY) continue;
      const a = advMap[i];
      const match = (matchValue === 1 ? (a > 0) : (a === 0));
      if (!match || compId[i] >= 0) continue;

      let head = 0, tail = 0, size = 0;
      const cid = sizes.length;
      compId[i] = cid;
      q[tail++] = i;

      while (head < tail) {
        const idx = q[head++];
        size++;

        const r = (idx / W) | 0;
        const c = idx % W;

        // Up
        if (r > 0) {
          const ni = idx - W;
          if (inside[ni] && flat[ni] === EMPTY && compId[ni] < 0) {
            const ma = advMap[ni];
            if (matchValue === 1 ? (ma > 0) : (ma === 0)) {
              compId[ni] = cid; q[tail++] = ni;
            }
          }
        }
        // Down
        if (r + 1 < H) {
          const ni = idx + W;
          if (inside[ni] && flat[ni] === EMPTY && compId[ni] < 0) {
            const ma = advMap[ni];
            if (matchValue === 1 ? (ma > 0) : (ma === 0)) {
              compId[ni] = cid; q[tail++] = ni;
            }
          }
        }
        // Left
        if (c > 0) {
          const ni = idx - 1;
          if (inside[ni] && flat[ni] === EMPTY && compId[ni] < 0) {
            const ma = advMap[ni];
            if (matchValue === 1 ? (ma > 0) : (ma === 0)) {
              compId[ni] = cid; q[tail++] = ni;
            }
          }
        }
        // Right
        if (c + 1 < W) {
          const ni = idx + 1;
          if (inside[ni] && flat[ni] === EMPTY && compId[ni] < 0) {
            const ma = advMap[ni];
            if (matchValue === 1 ? (ma > 0) : (ma === 0)) {
              compId[ni] = cid; q[tail++] = ni;
            }
          }
        }
      }
      sizes.push(size);
    }
    return { compId, sizes };
  }

  const pos = labelComponents(1); // adv > 0
  const tie = labelComponents(0); // adv == 0

  // Compute mouth counts (frontier entries adjacent to our cells) for each component
  const mouthPos = new Int16Array(pos.sizes.length);
  const mouthTie = new Int16Array(tie.sizes.length);

  for (let r = 0; r < H; r++) {
    const base = r * W;
    const row = grid[r];
    for (let c = 0; c < W; c++) {
      if (row[c] !== EMPTY) continue;
      const idx = base + c;

      // Count our adjacency
      let ourAdj = 0;

      if (r > 0) { const v = grid[r - 1][c]; if (v === id) ourAdj++; }
      if (r + 1 < H) { const v = grid[r + 1][c]; if (v === id) ourAdj++; }
      if (c > 0) { const v = grid[r][c - 1]; if (v === id) ourAdj++; }
      if (c + 1 < W) { const v = grid[r][c + 1]; if (v === id) ourAdj++; }

      if (ourAdj > 0) {
        const pid = pos.compId[idx];
        if (pid >= 0) mouthPos[pid]++;
        const tid = tie.compId[idx];
        if (tid >= 0) mouthTie[tid]++;
      }
    }
  }

  // Center bias prep
  const mid = (size - 1) / 2;
  const radius = mid;
  const maxR2 = radius * radius;

  // Build candidates with improved component-gate prioritization
  const candidates = [];
  for (let r = 0; r < H; r++) {
    const row = grid[r];
    const base = r * W;
    for (let c = 0; c < W; c++) {
      if (row[c] !== EMPTY) continue;
      const idx = base + c;

      // Adjacency counts
      let ourAdj = 0, enemyAdj = 0, emptyAdj = 0;

      // Up
      if (r > 0) {
        const v = grid[r - 1][c];
        if (v === id) ourAdj++;
        else if (v === EMPTY) emptyAdj++;
        else if (v !== null) enemyAdj++;
      }
      // Down
      if (r + 1 < H) {
        const v = grid[r + 1][c];
        if (v === id) ourAdj++;
        else if (v === EMPTY) emptyAdj++;
        else if (v !== null) enemyAdj++;
      }
      // Left
      if (c > 0) {
        const v = grid[r][c - 1];
        if (v === id) ourAdj++;
        else if (v === EMPTY) emptyAdj++;
        else if (v !== null) enemyAdj++;
      }
      // Right
      if (c + 1 < W) {
        const v = grid[r][c + 1];
        if (v === id) ourAdj++;
        else if (v === EMPTY) emptyAdj++;
        else if (v !== null) enemyAdj++;
      }

      if (ourAdj === 0) continue;

      const de_ = distEnemy[idx], do_ = distOur[idx];
      const De = (de_ < 0 ? 1000 : de_);
      const Do = (do_ < 0 ? 1000 : do_);
      const adv = advMap[idx];

      const deg = emptyAdj;
      const nearEnemy = (De <= 3) ? 1 : 0;
      const isChoke = (deg <= 1);

      // Component gate scores
      let gatePosScore = 0, gateTieScore = 0;
      if (adv > 0) {
        const pid = pos.compId[idx];
        if (pid >= 0) {
          const s = pos.sizes[pid] || 0;
          const m = mouthPos[pid] || 0;
          gatePosScore = Math.sqrt(s) * (4.0 / (m + 0.5));
        }
      } else if (adv === 0) {
        const tid = tie.compId[idx];
        if (tid >= 0) {
          const s = tie.sizes[tid] || 0;
          const m = mouthTie[tid] || 0;
          gateTieScore = Math.sqrt(s) * (2.5 / (m + 1));
        }
      }

      // Safety and center metrics
      const safeScore = (De === 1000 ? 14 : (De > 14 ? 14 : De));
      const dx = r - mid, dy = c - mid;
      const d2 = dx * dx + dy * dy;
      const centerScore = Math.max(0, (maxR2 - d2) / (maxR2 || 1));

      // Penalties and bonuses
      const enemyAdjPenalty = enemyAdj * 2.8 + (de_ === 1 ? 6 : 0);
      const tiePenalty = (adv === 0 ? (De < 10 ? 8 : 3) : 0);

      let chokeBonus = 0;
      if (isChoke) {
        chokeBonus += (deg === 0 ? 8 : 4);
        if (nearEnemy) chokeBonus += (deg === 0 ? 5 : 3);
      }
      if (enemyAdj >= 1 && deg <= 2) chokeBonus += 1.2 * enemyAdj;

      const expansionBonus = emptyAdj * 1.0 + (ourAdj >= 2 ? 0.5 : 0);

      let blockBonus = 0;
      if (adv <= 0 && deg <= 1 && De <= 2) {
        blockBonus = (deg === 0 ? 6 : 4) + 0.8 * enemyAdj;
      }

      let advClip = adv;
      if (advClip > 20) advClip = 20;
      else if (advClip < -10) advClip = -10;

      const score =
        4.0 * advClip +
        1.6 * safeScore +
        1.0 * expansionBonus +
        0.4 * ourAdj +
        0.6 * centerScore +
        chokeBonus -
        enemyAdjPenalty -
        tiePenalty +
        (adv > 0 ? (1.8 * gatePosScore) : 0) +
        (adv === 0 ? (0.9 * gateTieScore) : 0) +
        blockBonus;

      candidates.push({ r, c, s: score });
    }
  }

  if (candidates.length === 0) return [];

  candidates.sort((a, b) => b.s - a.s);
  const result = new Array(candidates.length);
  for (let i = 0; i < candidates.length; i++) {
    const p = candidates[i];
    result[i] = [p.r, p.c];
  }
  return result;
}
